// HasVideoModels applies the HasEdge predicate on the "video_models" edge.
func HasVideoModels() predicate.VideoCallTemplate {
	return predicate.VideoCallTemplate(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, VideoModelsTable, VideoModelsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasVideoModelsWith applies the HasEdge predicate on the "video_models" edge with a given conditions (other predicates).
func HasVideoModelsWith(preds ...predicate.VideoModel) predicate.VideoCallTemplate {
	return predicate.VideoCallTemplate(func(s *sql.Selector) {
		step := newVideoModelsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.VideoCallTemplate) predicate.VideoCallTemplate {
	return predicate.VideoCallTemplate(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.VideoCallTemplate) predicate.VideoCallTemplate {
	return predicate.VideoCallTemplate(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.VideoCallTemplate) predicate.VideoCallTemplate {
	return predicate.VideoCallTemplate(sql.NotPredicates(p))
}
